import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { FriendshipService } from '../../services/friendship.service';

@Component({
  selector: 'app-navbar',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './navbar.component.html',
  styleUrl: './navbar.component.css'
})
export class NavbarComponent implements OnInit {
  fullName: string = '';
  pendingRequestCount = 0;
  showMenu = false;
  showNotifications = false;

  constructor(
    private authService: AuthService,
    private friendshipService: FriendshipService,
    private router: Router
  ) {
    this.fullName = localStorage.getItem('fullName') || 'User';
  }

  ngOnInit() {
    this.loadPendingRequests();
    // Refresh pending requests every 30 seconds
    setInterval(() => {
      this.loadPendingRequests();
    }, 30000);
  }

  loadPendingRequests() {
    this.friendshipService.getPendingRequestCount().subscribe({
      next: (count) => {
        this.pendingRequestCount = count;
      },
      error: (err) => {
        console.error('Error loading pending requests:', err);
      }
    });
  }

  toggleMenu() {
    this.showMenu = !this.showMenu;
  }

  toggleNotifications() {
    this.showNotifications = !this.showNotifications;
  }

  goToProfile() {
    const userId = this.authService.getUserId();
    this.router.navigate([`/profile/${userId}`]);
    this.showMenu = false;
  }

  goToFriendRequests() {
    this.router.navigate(['/friend-requests']);
    this.showNotifications = false;
  }

  logout() {
    this.authService.logout();
    this.router.navigate(['/login']);
  }
}
